parameters.jsCode:
const body = $input.first().json.body;

return [{
  json: {
    agent_name:       body.agent_name       || '',
    google_url:       body.google_url       || '',
    zillow_url:       body.zillow_url       || '',
    client_name:      body.client_name      || '',
    client_phone:     '+1' + (body.client_phone || '').replace(/\D/g, ''),
    client_email:     body.client_email     || '',
    transaction_type: body.transaction_type || 'buyer',
    property_address: body.property_address || '',
    delay_days:       Number(body.delay_days) || 3,
  }
}];

const text = $input.first().json.content[0].text;
const prep = $('Prep Fields').first().json;

function extract(label, str) {
  const re = new RegExp(label + ':\\s*([\\s\\S]*?)(?=\\n[A-Z_]+:|$)');
  const m = str.match(re);
  return m ? m[1].trim() : '';
}

const smsText      = extract('SMS', text);
const emailSubject = extract('EMAIL_SUBJECT', text);
const emailBodyRaw = extract('EMAIL_BODY', text);

// Build SMS — append links
const linkLines = ['', '\u2b50 Leave a review:'];
if (prep.google_url) linkLines.push('Google: ' + prep.google_url);
if (prep.zillow_url) linkLines.push('Zillow: ' + prep.zillow_url);
const smsMessage = smsText + linkLines.join('\n');

// Build email HTML
const esc = s => (s || '').replace(/&/g, '&amp;');
const linkHtml = [
  prep.google_url ? `<a href="${esc(prep.google_url)}" style="color:#7FA9B8;">Leave a Google review</a>` : '',
  prep.zillow_url ? `<a href="${esc(prep.zillow_url)}" style="color:#7FA9B8;">Leave a Zillow review</a>` : '',
].filter(Boolean).join(' &nbsp;&middot;&nbsp; ');

const bodyHtml = emailBodyRaw
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\n\n/g, '</p><p style="font-size:15px;color:#3A3F48;line-height:1.6;margin:0 0 16px;">')
  .replace(/\n/g, '<br>');

const emailHtml = [
  '<div style="font-family:\'Inter\',Arial,sans-serif;max-width:520px;margin:0 auto;color:#0A0F1A;">',
  '  <div style="background:#0A0F1A;padding:32px 32px 28px;border-radius:8px 8px 0 0;">',
  '    <p style="font-size:11px;letter-spacing:0.15em;text-transform:uppercase;color:#7FA9B8;margin:0 0 10px;">Review Request</p>',
  `    <h1 style="font-size:22px;font-weight:700;color:#FAFAF7;margin:0;letter-spacing:-0.02em;">${emailSubject.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</h1>`,
  '  </div>',
  '  <div style="background:#FFFFFF;padding:32px;border:1px solid #E5E4DE;border-top:none;border-radius:0 0 8px 8px;">',
  `    <p style="font-size:15px;color:#3A3F48;line-height:1.6;margin:0 0 16px;">${bodyHtml}</p>`,
  `    <p style="font-size:14px;margin:0 0 28px;">${linkHtml}</p>`,
  '    <hr style="border:none;border-top:1px solid #E5E4DE;margin:0 0 20px;">',
  '    <p style="font-size:12px;color:#9EA3AA;margin:0;">Norr AI &nbsp;&middot;&nbsp; <a href="https://norrai.co" style="color:#9EA3AA;">norrai.co</a></p>',
  '  </div>',
  '</div>',
].join('\n');

return [{
  json: {
    sms_message:   smsMessage,
    email_subject: emailSubject,
    email_html:    emailHtml,
    client_phone:  prep.client_phone,
    client_email:  prep.client_email,
  }
}];

